SELECT  
WHERE wi.user_id = #{userId} AND wi.asset_kind = #{assetKind}
  AND ((wi.asset_kind = 'FUND' AND f.fund_code = #{assetCode})
    OR (wi.asset_kind = 'STOCK' AND sm.stock_code = #{assetCode}
